import React, { useState, useEffect } from "react";
import MetricsChart from "./MetricsChart";
import DocumentCard from "./DocumentCard";

// ✅ MOVED OUTSIDE (fixes eslint warning)
const agents = ["Query", "Router", "Retriever", "Reasoning", "Formatter"];

function Message({ msg }) {
  const [showOptions, setShowOptions] = useState(false);
  const [activeAgent, setActiveAgent] = useState(0);

  // ✅ AGENT ANIMATION (clean + no warning)
  useEffect(() => {
    if (msg.loading) {
      let i = 0;

      const interval = setInterval(() => {
        setActiveAgent(i);
        i++;
        if (i >= agents.length) i = 0;
      }, 700);

      return () => clearInterval(interval);
    }
  }, [msg.loading]);

  // 👤 USER MESSAGE
  if (msg.type === "user") {
    return <div className="user-msg">{msg.text}</div>;
  }

  // ⏳ LOADING STATE
  if (msg.loading) {
    return (
      <div className="ai-msg">
        <div className="pipeline-live">
          {agents.map((agent, i) => (
            <span key={i} className={i === activeAgent ? "active" : ""}>
              {agent}
            </span>
          ))}
        </div>
        <div className="thinking">Processing agents...</div>
      </div>
    );
  }

  // ✨ SMART ANSWER PARSING
  const answerSteps = msg.answer
    ?.split(/\n|•|\d+\./)
    .filter((p) => p.trim());

  // 📋 COPY FUNCTIONS
  const copyFull = () => {
    navigator.clipboard.writeText(msg.answer || "");
    setShowOptions(false);
  };

  const copyAnswerOnly = () => {
    navigator.clipboard.writeText(answerSteps.join("\n"));
    setShowOptions(false);
  };

  return (
    <div className="ai-msg">

      {/* ✨ FINAL ANSWER */}
      <div className="section-card">
        <h4>Final Answer</h4>

        <div className="answer-steps">
          {answerSteps.map((step, i) => (
            <div key={i} className="step-card">
              <span className="step-number">{i + 1}</span>
              <div>{step}</div>
            </div>
          ))}
        </div>
      </div>

      {/* 📄 DOCUMENTS */}
      <div className="section-card">
        <h4>Top Sources</h4>
        {msg.explanations?.map((doc, i) => (
          <DocumentCard key={i} doc={doc} />
        ))}
      </div>

      {/* 📊 METRICS */}
      <div className="section-card">
        <h4>Answer Quality</h4>

        {/* CONFIDENCE */}
        <div className="confidence-text">
          Confidence: <strong>{msg.metrics?.["Confidence Level"]}</strong>
        </div>

        {/* PIE CHART */}
        <MetricsChart metrics={msg.metrics} />

        {/* SIMPLE LABELS */}
        <div className="metrics-list">
          <div>
            Match:{" "}
            {(msg.metrics?.["Answer-Context Similarity"] * 100 || 0).toFixed(1)}%
          </div>
          <div>
            Relevance:{" "}
            {(msg.metrics?.["Query-Context Relevance"] * 100 || 0).toFixed(1)}%
          </div>
          <div>
            Coverage:{" "}
            {(msg.metrics?.["Context Coverage"] * 100 || 0).toFixed(1)}%
          </div>
        </div>

        {/* RESPONSE TIME */}
        <div className="response-time">
          ⏱ Response Time: {msg.response_time || 0}s
        </div>
      </div>

      {/* 📋 COPY */}
      <div className="copy-container bottom-copy">
        <button
          className="copy-btn"
          onClick={() => setShowOptions(!showOptions)}
        >
          📋
        </button>

        {showOptions && (
          <div className="copy-dropdown">
            <div onClick={copyFull}>Copy full</div>
            <div onClick={copyAnswerOnly}>Copy answer</div>
          </div>
        )}
      </div>

    </div>
  );
}

export default Message;
